import { IVendorRepository } from "@src/modules/kallisto-hub/application/interfaces/repositories/IVendorRepository";
import { ICreateVendorUseCase } from "@src/modules/kallisto-hub/application/interfaces/usecases/vendor/ICreateVendorUseCase";
import {
  CreateVendorRequestDTO,
  VendorResultDTO,
} from "@src/modules/kallisto-hub/application/dto/VendorDTO";
import { VendorEntity } from "@src/modules/kallisto-hub/domain/entities/VendorEntity";
import { AppError, ErrorCode } from "@packages/common/errors";
import { HubMessages } from "@packages/common/messages";
import { HttpStatus } from "@packages/common/enums";

export class CreateVendorUseCase implements ICreateVendorUseCase {
  constructor(private readonly _vendorRepository: IVendorRepository) {}

  async execute(dto: CreateVendorRequestDTO): Promise<VendorResultDTO> {
    // 1. Check if vendor with same email exists
    const existing = await this._vendorRepository.findByEmail(dto.email);
    if (existing) {
      throw new AppError(
        ErrorCode.VENDOR_ALREADY_EXISTS,
        HubMessages.VENDOR_ALREADY_EXISTS,
        HttpStatus.CONFLICT,
      );
    }

    // 2. Create vendor entity
    const now = new Date();
    const vendor: VendorEntity = {
      id: "", // Generated by repository/DB
      vendorCode: "", // Generated by repository/DB
      vendorType: dto.vendorType,
      companyName: dto.companyName,
      GSTIN: dto.GSTIN,
      brandName: dto.brandName,
      email: dto.email,
      phone: dto.phone,
      officeAddress: dto.officeAddress,
      city: dto.city,
      district: dto.district,
      state: dto.state || "Kerala",
      pincode: dto.pincode,
      country: dto.country || "India",
      isVerified: false,
      isActive: true,
      createdAt: now,
      updatedAt: now,
    };

    const created = await this._vendorRepository.create(vendor);

    // 3. Map to result
    return {
      id: created.id,
      vendorCode: created.vendorCode,
      vendorType: created.vendorType,
      companyName: created.companyName,
      brandName: created.brandName,
      profilePicture: created.profilePicture,
      email: created.email,
      phone: created.phone,
      city: created.city,
      isVerified: created.isVerified,
      isActive: created.isActive,
    };
  }
}
